// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('hover', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('hover', async function() {
    await driver.get("http://localhost:4200/admin-user/add-user");
    await driver.manage().window().setRect({ width: 1920, height: 1040 });
    {
      const element = await driver.findElement(By.name("Search"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    await driver.sleep(1000);
    vars["searchButtonBackground"] = await driver.executeScript("return getComputedStyle(document.getElementsByName(\"Search\")[0]).backgroundColor");
    assert(vars["searchButtonBackground"].toString() == "rgb(0, 135, 77)");
    vars["searchButtonColor"] = await driver.executeScript("return getComputedStyle(document.getElementsByName(\"Search\")[0]).color");
    assert(vars["searchButtonColor"].toString() == "rgb(255, 255, 255)");
    await driver.findElement(By.name("Search")).click();
    await driver.sleep(8000);
    await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/div/div/div/div/div/div/div/table/tbody/tr/td/label/span/input")).click();
    {
      const element = await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/div/form/button[2]"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    vars["searchAddBackground"] = await driver.executeScript("return getComputedStyle(document.getElementsByName(\"Search\")[1]).backgroundColor");
    await driver.sleep(1000);
    assert(vars["searchAddBackground"].toString() == "rgb(255, 255, 255)");
    vars["searchAddColor"] = await driver.executeScript("return getComputedStyle(document.getElementsByName(\"Search\")[1]).color");
    assert(vars["searchAddColor"].toString() == "rgb(0, 135, 77)");
  });
});
